@import"https://fonts.googleapis.com/css2?family=Ma+Shan+Zheng&display=swap";.point-bar{position:sticky;top:0;display:flex;align-items:center;gap:.9rem;padding:.85rem 1.4rem;background:linear-gradient(180deg, rgba(10, 9, 13, 0.98) 0%, rgba(5, 4, 7, 0.98) 100%);border-bottom:1px solid rgba(207,200,184,.18);color:#cfc8b8;font-family:"STKaiti","KaiTi","FangSong","Songti SC","SimSun",serif;font-size:1.05rem;z-index:10;letter-spacing:.1em;box-shadow:0 2px 14px rgba(0,0,0,.6);transition:background .4s ease,border-color .4s ease}@media(max-width: 519px){.point-bar{padding:.55rem .6rem;gap:.35rem;font-size:.85rem;flex-wrap:wrap}}@media(min-width: 520px)and (max-width: 767px){.point-bar{padding:.7rem 1rem;font-size:.95rem}}.point-bar .orn{color:#a8a293;opacity:.55;font-size:1rem;text-shadow:0 0 6px rgba(207,200,184,.3)}@media(max-width: 519px){.point-bar .orn{font-size:.8rem}}.point-bar .label{color:#a09888;font-size:1rem}@media(max-width: 519px){.point-bar .label{font-size:.8rem}}.point-bar .value{display:inline-flex;align-items:baseline;gap:.25rem}.point-bar .value .num{color:#cfc8b8;background:linear-gradient(180deg, #e8e0d0 0%, #cfc8b8 50%, #a8a293 100%);-webkit-background-clip:text;background-clip:text;-webkit-text-fill-color:rgba(0,0,0,0);text-shadow:0 0 12px rgba(207,200,184,.18);font-family:"STKaiti","KaiTi","FangSong","Songti SC","SimSun",serif;letter-spacing:.05em;font-size:1.5em;font-weight:bold}.point-bar .value .slash{color:#7a7668;margin:0 .25em}.point-bar .value .total{color:#a8a293;font-size:1em}.point-bar .warn{color:#c64545;font-size:.95rem;margin-left:auto;margin-right:.5rem;padding:.25rem .7rem;background:rgba(80,15,15,.4);border:1px solid rgba(198,69,69,.5);border-radius:6px;text-shadow:0 0 8px rgba(198,69,69,.5);animation:warn-pulse 1.4s ease-in-out infinite}@media(max-width: 519px){.point-bar .warn{font-size:.78rem;padding:.2rem .5rem;margin-right:0;margin-left:0;width:100%;text-align:center}}.point-bar.超支{background:linear-gradient(180deg, rgba(50, 10, 10, 0.98) 0%, rgba(25, 5, 5, 0.98) 100%);border-bottom-color:#8a2424}.point-bar.超支 .value .num{background:linear-gradient(180deg, #d8a0a0 0%, #a83333 55%, #6b1a1a 100%);-webkit-background-clip:text;background-clip:text;-webkit-text-fill-color:rgba(0,0,0,0);font-family:"STKaiti","KaiTi","FangSong","Songti SC","SimSun",serif;filter:drop-shadow(0 0 4px rgba(168, 51, 51, 0.4))}@keyframes warn-pulse{0%,100%{opacity:1}50%{opacity:.6}}